sql:
SELECT u.user_name, u.email, dv.result
FROM users u
JOIN data_validations dv ON u.user_id = dv.validation_by;

SELECT layer, property 
FROM sensors 
WHERE sensor_id = 1;

SELECT *
FROM data_validations
WHERE validation_by = 'Specific User ID';

SELECT data_id, value
FROM data
WHERE MOD(data_id, 2) = 1 AND value > (SELECT AVG(value) FROM data);

SELECT DISTINCT layer
FROM sensors
WHERE property = 'mobilitymadrid:layers';

SELECT sensor_id, layer 
FROM sensors 
WHERE sensor_id > 10;

SELECT AVG(installation_date) AS avg_sensor_installation_date
FROM sensors
WHERE status = 'active';

SELECT sensor_id
FROM sensor_owners
WHERE owner_id = 1 AND end_date IS NULL;

SELECT 
  (SELECT owner_name FROM owners WHERE owner_id = (
    SELECT owner_id FROM sensor_owners WHERE sensor_id = 0
  )) AS owner_name, 
  (SELECT schema_name FROM schemas WHERE schema_id = (
    SELECT schema_id FROM data WHERE data_id = 1
  )) AS schema_name, 
  (SELECT user_name FROM users WHERE user_id = (
    SELECT validation_by FROM data_validations WHERE data_id = 1
  )) AS user_name;

external_knowledge:
- 'John Doe' is a commonly used placeholder name to refer to the specific owner in the query;
- 'Mobile' is a specific type of data layer closely associated with mobile communication data;
- 'Valid data points' are those that passed through a validation process, ensuring their accuracy or reliability;
- The period 'past year' refers to the date range from now back to exactly one year ago;
- 'A dozen' is a colloquial term for twelve, used here to indicate that the query requires sensors to have more than 10 data points.
